const src = $node["Gemini Analyse Finale"].json || {};

const rawContent = src?.choices?.[0]?.message?.content || src?.message || '';
const rawText = typeof rawContent === 'string' ? rawContent : JSON.stringify(rawContent || {});

const safeStringArray = (value) => Array.isArray(value)
  ? value.map((v) => String(v || '').trim()).filter(Boolean)
  : [];

const extractJsonCandidates = (text) => {
  const candidates = [];
  if (!text || typeof text !== 'string') return candidates;

  const trimmed = text.trim();
  if (trimmed.startsWith('{') && trimmed.endsWith('}')) candidates.push(trimmed);

  const fenced = trimmed.match(/```(?:json)?\s*([\s\S]*?)\s*```/i);
  if (fenced?.[1]) candidates.push(fenced[1].trim());

  const first = trimmed.indexOf('{');
  const last = trimmed.lastIndexOf('}');
  if (first !== -1 && last !== -1 && last > first) {
    candidates.push(trimmed.slice(first, last + 1));
  }

  return Array.from(new Set(candidates));
};

let parsed = null;
for (const candidate of extractJsonCandidates(rawText)) {
  try {
    parsed = JSON.parse(candidate);
    if (parsed && typeof parsed === 'object') break;
  } catch (e) {}
}

const toDetailed = (list) => safeStringArray(list).map((text) => {
  const l = text.toLowerCase();

  let productType = 'Targeted skincare action';
  let why = 'Supports the priority concerns detected in your analysis and helps improve skin stability.';
  let how = 'Apply on clean skin, start gradually if this is a new active, and monitor tolerance over 1-2 weeks.';
  let when = 'As indicated by your routine step';
  let frequency = '3-7x per week based on tolerance';
  let cautions = 'Stop or reduce frequency if irritation appears.';

  if (/(spf|sunscreen|uv|sun)/.test(l)) {
    productType = 'Photoprotection';
    why = 'Prevents UV-triggered inflammation, pigmentation and premature aging, which can worsen current concerns.';
    how = 'Apply generously as the last morning step and reapply every 2-3 hours when outdoors.';
    when = 'Every morning and before sun exposure';
    frequency = 'Daily';
    cautions = 'Do not rely on makeup SPF alone.';
  } else if (/(vitamin c|ascorbic)/.test(l)) {
    productType = 'Antioxidant serum';
    why = 'Helps reduce oxidative stress, brighten uneven tone and support collagen protection.';
    how = 'Use 2-4 drops on dry skin before moisturizer, then seal with SPF in the morning.';
    when = 'Morning';
    frequency = 'Daily or every other day initially';
    cautions = 'If stinging persists, reduce frequency and avoid layering with strong acids at the same time.';
  } else if (/(retinol|retinoid)/.test(l)) {
    productType = 'Retinoid treatment';
    why = 'Supports texture refinement, anti-aging and long-term acne control.';
    how = 'Apply a pea-sized amount at night on dry skin, followed by moisturizer.';
    when = 'Evening';
    frequency = '2-4 nights/week to start';
    cautions = 'Avoid if pregnant and avoid combining with strong exfoliants the same night.';
  } else if (/(niacinamide)/.test(l)) {
    productType = 'Barrier-balancing serum';
    why = 'Helps regulate sebum, calm redness and reinforce barrier resilience.';
    how = 'Apply a thin layer after cleansing and before moisturizer.';
    when = 'Morning or evening';
    frequency = 'Daily';
    cautions = 'Patch test if skin is highly reactive.';
  } else if (/(cleanser|double cleanse|nettoy)/.test(l)) {
    productType = 'Cleanser step';
    why = 'Removes sweat, sunscreen and impurities to reduce congestion and irritation triggers.';
    how = 'Massage gently for 30-60 seconds, rinse with lukewarm water, avoid over-cleansing.';
    when = 'Morning and/or evening';
    frequency = 'Daily';
    cautions = 'Avoid harsh surfactants if your skin is dry or sensitive.';
  } else if (/(moistur|ceramide|barrier|hydrat)/.test(l)) {
    productType = 'Barrier moisturizer';
    why = 'Improves hydration retention and reduces transepidermal water loss.';
    how = 'Apply on slightly damp skin after treatment serums.';
    when = 'Morning and evening';
    frequency = 'Daily';
    cautions = 'Choose non-comedogenic textures if acne-prone.';
  }

  return {
    title: text,
    description: text,
    why,
    how,
    when,
    frequency,
    productType,
    cautions
  };
});

const recommendations = parsed?.recommendations && typeof parsed.recommendations === 'object'
  ? parsed.recommendations
  : {};

const immediate = safeStringArray(recommendations.immediate);
const weekly = safeStringArray(recommendations.weekly);
const avoid = safeStringArray(recommendations.avoid);

const detailedImmediate = Array.isArray(recommendations.detailedImmediate) && recommendations.detailedImmediate.length
  ? recommendations.detailedImmediate
  : toDetailed(immediate);

const detailedWeekly = Array.isArray(recommendations.detailedWeekly) && recommendations.detailedWeekly.length
  ? recommendations.detailedWeekly
  : toDetailed(weekly);

const detailedAvoid = Array.isArray(recommendations.detailedAvoid) && recommendations.detailedAvoid.length
  ? recommendations.detailedAvoid
  : toDetailed(avoid);

const normalizeAnalysisText = (value) => {
  if (typeof value === 'string') return value.trim();
  if (!value || typeof value !== 'object') return '';

  const source = value;
  const candidates = [source.analysis, source.text, source.content, source.summary, source.message];
  for (const candidate of candidates) {
    if (typeof candidate === 'string' && candidate.trim()) return candidate.trim();
  }

  return '';
};

const finalAnalysis = normalizeAnalysisText(parsed?.analysis)
  || rawText.trim()
  || String(src?.error?.message || '').trim()
  || 'Skin analysis is ready.';

return {
  status: 'complete',
  analysis: finalAnalysis,
  score: Number(parsed?.score || 80),
  recommendations: {
    immediate,
    weekly,
    avoid,
    detailedImmediate,
    detailedWeekly,
    detailedAvoid
  }
};

