const base = $node["Prepare Routine Context"].json || {};
const src = $node["Generate Routine"].json || {};

const allowedSkinTypes = new Set(['OILY', 'DRY', 'COMBINATION', 'SENSITIVE', 'NORMAL']);

const isValidStepList = (list) => Array.isArray(list) && list.every((item, idx) =>
  Number(item?.step) === idx + 1 &&
  typeof item?.name === 'string' && item.name.trim().length > 0 &&
  typeof item?.instruction === 'string' && item.instruction.trim().length > 0 &&
  String(item?.frequency || '').toLowerCase() === 'daily'
);

const isValidWeekly = (list) => Array.isArray(list) && list.every((item) =>
  typeof item?.day === 'string' && item.day.trim().length > 0 &&
  typeof item?.focus === 'string' && item.focus.trim().length > 0 &&
  typeof item?.instruction === 'string' && item.instruction.trim().length > 0
);

const isValidRoutine = (obj) => {
  if (!obj || typeof obj !== 'object') return false;
  if (typeof obj.title !== 'string' || !obj.title.trim()) return false;
  if (!allowedSkinTypes.has(String(obj.skinType || '').toUpperCase())) return false;
  if (!isValidStepList(obj.morning)) return false;
  if (!isValidStepList(obj.evening)) return false;
  if (!isValidWeekly(obj.weekly)) return false;
  if (!Array.isArray(obj.warnings) || !obj.warnings.every((w) => typeof w === 'string')) return false;
  if (Number(obj.durationWeeks) !== 4) return false;
  return true;
};

let generatedRoutine = null;
let routineGenerationError = null;

try {
  if (src?.error) {
    throw new Error(String(src.error.message || src.error || 'Routine generation request failed'));
  }

  const raw = src?.choices?.[0]?.message?.content || '{}';
  const text = typeof raw === 'string' ? raw : JSON.stringify(raw);
  const parsed = JSON.parse(text);

  if (!isValidRoutine(parsed)) {
    throw new Error('Routine JSON does not match expected schema');
  }

  generatedRoutine = {
    ...parsed,
    skinType: String(parsed.skinType).toUpperCase()
  };
} catch (error) {
  routineGenerationError = String(error?.message || error || 'Unknown routine generation error');
}

return {
  ...base,
  generatedRoutine,
  routineGenerationError
};

const parsedRoutine = $node["Parser Routine JSON"]?.json || {};
const saveResult = $node["Save Routine DB"]?.json || $json || {};

if (parsedRoutine.routineGenerationError) {
  console.error('[Routine] Generation failed:', parsedRoutine.routineGenerationError);
}

if (saveResult.error) {
  console.error('[Routine] Save DB failed:', saveResult.error);
}

if (!parsedRoutine.routineGenerationError && !saveResult.error) {
  console.log('[Routine] Routine generated and persisted successfully.');
}

const generatedRoutine = parsedRoutine.generatedRoutine && typeof parsedRoutine.generatedRoutine === 'object'
  ? parsedRoutine.generatedRoutine
  : {};

const routine = {
  morning: Array.isArray(generatedRoutine.morning) ? generatedRoutine.morning : [],
  evening: Array.isArray(generatedRoutine.evening) ? generatedRoutine.evening : [],
  morningDetailed: Array.isArray(generatedRoutine.morning) ? generatedRoutine.morning : [],
  eveningDetailed: Array.isArray(generatedRoutine.evening) ? generatedRoutine.evening : []
};

const recommendations = parsedRoutine.recommendations && typeof parsedRoutine.recommendations === 'object'
  ? parsedRoutine.recommendations
  : { immediate: [], weekly: [], avoid: [], detailedImmediate: [], detailedWeekly: [], detailedAvoid: [] };

return {
  status: 'complete',
  analysis: String(parsedRoutine.analysis || ''),
  score: Number(parsedRoutine.score || 0),
  recommendations,
  routine
};
